```typescript
@Component(metadata: ComponentMetadata)
```
Decorator that marks a class as an Angular component and supplies configuration metadata including template, styles, selector, and change detection strategy.

```typescript
@Component({
  selector: 'app-root',
  standalone: true,
  templateUrl: './app.component.html',
  styleUrls: ['./app.component.css'],
  changeDetection: ChangeDetectionStrategy.OnPush
})
export class AppComponent {}
```

```typescript
@NgModule(metadata: NgModuleMetadata)
```
Decorator that marks a class as an NgModule with declarations, imports, providers, exports, and bootstrap arrays.

```typescript
@NgModule({
  declarations: [AppComponent],
  imports: [BrowserModule],
  providers: [],
  bootstrap: [AppComponent]
})
export class AppModule {}
```

```typescript
@Injectable(options?: { providedIn: 'root' | 'platform' | 'any' | Type<any> | null })
```
Decorator that marks a class as available to be provided and injected as a dependency.

```typescript
@Injectable({ providedIn: 'root' })
export class DataService {
  constructor(private http: HttpClient) {}
}
```

```typescript
@Directive(metadata: DirectiveMetadata)
```
Decorator that marks a class as an Angular directive with a CSS selector.

```typescript
@Directive({
  selector: '[appHighlight]',
  standalone: true
})
export class HighlightDirective {}
```

```typescript
@Pipe(metadata: { name: string; standalone?: boolean; pure?: boolean })
```
Decorator that marks a class as a pipe and supplies a name for template use.

```typescript
@Pipe({ name: 'truncate', standalone: true })
export class TruncatePipe implements PipeTransform {
  transform(value: string, limit: number): string {
    return value.length > limit ? value.substring(0, limit) + '...' : value;
  }
}
```

```typescript
@Input(bindingPropertyName?: string)
```
Decorator that marks a class field as an input property. Bound to a DOM property in the template.

```typescript
@Input() title: string = '';
@Input({ required: true }) id!: number;
@Input({ alias: 'userName' }) name = '';
```

```typescript
@Output(bindingPropertyName?: string)
```
Decorator that marks a class field as an output property. Used with EventEmitter.

```typescript
@Output() clicked = new EventEmitter<void>();
@Output('onSave') saved = new EventEmitter<Data>();
```

```typescript
@ViewChild(selector: Type<any> | string, opts?: { read?: any; static?: boolean })
```
Configures a view query for the first matching element or directive in the view DOM.

```typescript
@ViewChild('myInput') inputRef!: ElementRef;
@ViewChild(ChildComponent) child!: ChildComponent;
```

```typescript
@ViewChildren(selector: Type<any> | string, opts?: { read?: any })
```
Configures a view query for all matching elements or directives.

```typescript
@ViewChildren(ItemComponent) items!: QueryList<ItemComponent>;
```

```typescript
@ContentChild(selector: Type<any> | string, opts?: { read?: any; static?: boolean })
```
Configures a content query for the first matching element in projected content.

```typescript
@ContentChild(TemplateRef) template!: TemplateRef<any>;
```

```typescript
@ContentChildren(selector: Type<any> | string, opts?: { read?: any; descendants?: boolean })
```
Configures a content query for all matching elements in projected content.

```typescript
@ContentChildren(TabComponent) tabs!: QueryList<TabComponent>;
```

```typescript
@HostBinding(hostPropertyName?: string)
```
Marks a DOM property or attribute as a host-binding property.

```typescript
@HostBinding('class.active') isActive = false;
@HostBinding('style.color') color = 'red';
```

```typescript
@HostListener(eventName: string, args?: string[])
```
Declares a host event listener. Angular invokes the decorated method when the host element emits the event.

```typescript
@HostListener('click', ['$event'])
onClick(event: MouseEvent): void { }
```

```typescript
interface OnInit {
  ngOnInit(): void;
}
```
Lifecycle hook called once after the first `ngOnChanges`. Use for initialization logic.

```typescript
export class MyComponent implements OnInit {
  ngOnInit(): void {
    // initialization
  }
}
```

```typescript
interface OnDestroy {
  ngOnDestroy(): void;
}
```
Lifecycle hook called when the directive/component is destroyed. Use for cleanup.

```typescript
export class MyComponent implements OnDestroy {
  ngOnDestroy(): void {
    this.subscription.unsubscribe();
  }
}
```

```typescript
interface OnChanges {
  ngOnChanges(changes: SimpleChanges): void;
}
```
Lifecycle hook called when any data-bound input property changes. Receives a `SimpleChanges` object.

```typescript
interface AfterViewInit {
  ngAfterViewInit(): void;
}
```
Lifecycle hook called after the component's view and child views have been fully initialized.

```typescript
interface AfterContentInit {
  ngAfterContentInit(): void;
}
```
Lifecycle hook called after Angular projects external content into the component.

```typescript
interface DoCheck {
  ngDoCheck(): void;
}
```
Lifecycle hook called during every change detection run. Use to detect changes Angular cannot.

```typescript
interface AfterViewChecked {
  ngAfterViewChecked(): void;
}
```
Lifecycle hook called after every check of the component's view.

```typescript
interface AfterContentChecked {
  ngAfterContentChecked(): void;
}
```
Lifecycle hook called after every check of projected content.

```typescript
function signal<T>(initialValue: T, options?: CreateSignalOptions<T>): WritableSignal<T>
```
Creates a writable signal with an initial value. Signals are reactive primitives that notify consumers when they change.

```typescript
const count = signal(0);
count.set(5);
count.update(v => v + 1);
console.log(count()); // 6
```

```typescript
function effect(effectFn: () => void, options?: CreateEffectOptions): EffectRef
```
Creates an effect that runs a side-effectful function whenever one of the signals it reads changes.

```typescript
effect(() => {
  console.log('Count changed:', this.count());
});
```

```typescript
function resource<T, R>(options: ResourceOptions<T, R>): ResourceRef<R>
```
Creates a resource that loads data asynchronously based on a reactive request signal.

```typescript
const userData = resource({
  request: () => this.userId(),
  loader: async ({ request: id }) => fetch(`/api/users/${id}`)
});
```

```typescript
class EventEmitter<T = any> extends Subject<T>
```
Use in directives and components to emit custom events.

```typescript
@Output() clicked = new EventEmitter<MouseEvent>();
this.clicked.emit(event);
```

```typescript
enum ChangeDetectionStrategy {
  OnPush = 0,
  Default = 1
}
```
Defines the change detection strategy. `OnPush` checks only when inputs change or events fire.

```typescript
@Component({
  changeDetection: ChangeDetectionStrategy.OnPush
})
```

```typescript
class ElementRef<T = any> {
  nativeElement: T;
}
```
Wrapper around a native element. Use with caution as direct DOM access bypasses Angular's templating.

```typescript
class NgZone
```
Service for executing work inside or outside Angular's zone.

```typescript
this.ngZone.runOutsideAngular(() => {
  // No change detection triggered
});
```

```typescript
class FormGroup extends AbstractControl
```
Tracks the value and validity of a group of FormControl instances.

```typescript
const form = new FormGroup({
  name: new FormControl(''),
  email: new FormControl('', Validators.email)
});
```

```typescript
class FormBuilder
```
Reduces boilerplate for creating reactive forms.

```typescript
constructor(private fb: FormBuilder) {}
this.form = this.fb.group({
  name: ['', Validators.required],
  email: ['', [Validators.required, Validators.email]]
});
```

```typescript
interface HttpInterceptor {
  intercept(req: HttpRequest<any>, next: HttpHandler): Observable<HttpEvent<any>>;
}
```
Interface for interceptors that transform outgoing requests and incoming responses.

```typescript
function provideRouter(routes: Routes, ...features: RouterFeatures[]): EnvironmentProviders
```
Sets up router providers for standalone apps.

```typescript
bootstrapApplication(AppComponent, {
  providers: [provideRouter(routes, withComponentInputBinding())]
});
```

```typescript
interface ApplicationConfig {
  providers: Array<Provider | EnvironmentProviders>;
}
```
Configuration for bootstrapping a standalone application.

```html
{{ dateValue | date:'short' }}
{{ dateValue | date:'yyyy-MM-dd' }}
```
Formats a date value according to locale rules and a format string.

```html
@for (item of map | keyvalue; track item.key) {
  {{ item.key }}: {{ item.value }}
}
```
Transforms Object or Map into an array of key-value pairs.
